def _delta_rel(before_pct: float, after_pct: float) -> float:
    delta_abs = after_pct - before_pct
    if before_pct != 0:
        return (delta_abs / abs(before_pct)) * 100
    if delta_abs > 0:
        return float("inf")
    if delta_abs < 0:
        return float("-inf")
    return 0.0

