fn delta_rel(before_pct: f64, after_pct: f64) -> f64 {
    let delta_abs = after_pct - before_pct;
    if before_pct != 0.0 {
        delta_abs / before_pct.abs() * 100.0
    } else if delta_abs > 0.0 {
        f64::INFINITY
    } else if delta_abs < 0.0 {
        f64::NEG_INFINITY
    } else {
        0.0
