/// Correctly rounded num/den as f64 (round half to even), matching CPython int.__truediv__.
pub(crate) fn int_ratio(num: i128, den: i128) -> f64 {
    if num == 0 { return 0.0; }
    let negative = (num < 0) != (den < 0);
    let (n, d) = (num.unsigned_abs(), den.unsigned_abs());
    let nbits = 128 - n.leading_zeros() as i32;
    let dbits = 128 - d.leading_zeros() as i32;
    // Scale so the integer quotient carries 55 significant bits (53 mantissa + round),
    // with the division remainder as the sticky bit.
    let shift = 55 - (nbits - dbits); // nbits+shift = 55+dbits <= 119 < 128: no overflow
    let (mut q, r) = if shift >= 0 {
        let s = n << shift; (s / d, s % d)
    } else {
        let sd = d << (-shift) as u32; (n / sd, n % sd)
    };
    let mut exp = -shift; // value ~= q * 2^exp
    let mut sticky = r != 0;
    if q >> 55 != 0 { sticky |= q & 1 != 0; q >>= 1; exp += 1; } // 56-bit case
    // q now has exactly 55 bits: mantissa(54..1) + round bit(0)
    let round = q & 1 != 0;
    let mut m = q >> 1; exp += 1;
    if round && (sticky || m & 1 != 0) { m += 1; } // half-to-even
    let magnitude = (m as f64) * (exp as f64).exp2(); // or libm-style ldexp(m as f64, exp)
    if negative { -magnitude } else { magnitude }
}

